<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Bouncing Ball Physics Playground</title>
  <style>
    :root {
      color-scheme: dark;
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background: #090b12;
      color: #eef2ff;
    }

    * {
      box-sizing: border-box;
    }

    body {
      min-width: 700px;
      min-height: 100vh;
      margin: 0;
      display: grid;
      place-items: center;
      background:
        radial-gradient(circle at 50% 20%, rgba(71, 85, 180, 0.18), transparent 38rem),
        linear-gradient(180deg, #10131f, #070910);
    }

    main {
      width: 680px;
      padding: 24px 20px;
      text-align: center;
    }

    h1 {
      margin: 0 0 6px;
      font-size: 25px;
      letter-spacing: 0.02em;
    }

    .subtitle {
      margin: 0 0 18px;
      color: #9ca6c6;
      font-size: 14px;
    }

    .canvas-shell {
      width: 640px;
      margin: 0 auto;
      padding: 1px;
      border-radius: 18px;
      background: linear-gradient(135deg, #5865d8, #283052 45%, #9c4fcc);
      box-shadow:
        0 24px 70px rgba(0, 0, 0, 0.52),
        0 0 42px rgba(91, 104, 220, 0.13);
    }

    #sim {
      display: block;
      width: 640px;
      height: 500px;
      border-radius: 17px;
      background: #0c101b;
      cursor: crosshair;
      touch-action: none;
    }

    .controls {
      display: flex;
      justify-content: center;
      gap: 10px;
      margin-top: 16px;
    }

    button {
      min-width: 118px;
      border: 1px solid #353d61;
      border-radius: 11px;
      padding: 10px 16px;
      color: #eef1ff;
      background: linear-gradient(180deg, #252b46, #181c2f);
      font: inherit;
      font-size: 14px;
      font-weight: 700;
      cursor: pointer;
      box-shadow: 0 7px 18px rgba(0, 0, 0, 0.25);
      transition: transform 100ms ease, border-color 100ms ease, filter 100ms ease;
    }

    button:hover {
      border-color: #6975c8;
      filter: brightness(1.12);
      transform: translateY(-1px);
    }

    button:active {
      transform: translateY(1px) scale(0.98);
    }

    #drop {
      border-color: #5968d7;
      background: linear-gradient(180deg, #5868dc, #3946a7);
    }

    #clear {
      color: #ffc9d1;
    }

    .hint {
      margin: 13px 0 0;
      color: #727c9d;
      font-size: 12px;
    }
  </style>
</head>
<body>
  <main>
    <h1>Bouncing Ball Playground</h1>
    <p class="subtitle">Gravity, momentum, and a little bit of chaos.</p>

    <div class="canvas-shell">
      <canvas id="sim" width="640" height="500" aria-label="Bouncing ball simulation"></canvas>
    </div>

    <div class="controls">
      <button id="drop" type="button">Drop Ball</button>
      <button id="play" type="button">Pause</button>
      <button id="clear" type="button">Clear</button>
    </div>

    <p class="hint">Click anywhere in the arena to launch a ball.</p>
  </main>

  <script>
    (() => {
      "use strict";

      const canvas = document.getElementById("sim");
      const ctx = canvas.getContext("2d");
      const dropButton = document.getElementById("drop");
      const playButton = document.getElementById("play");
      const clearButton = document.getElementById("clear");

      const W = 640;
      const H = 500;
      const GRAVITY = 0.38;
      const RESTITUTION = 0.82;
      const state = [];
      let running = true;
      let previousTime = performance.now();

      const palette = [
        ["#8ee7ff", "#3977ff"],
        ["#ffc87a", "#f05b72"],
        ["#d5a1ff", "#7c4dff"],
        ["#93ffd1", "#25a99a"],
        ["#ff9ed1", "#c8409a"],
        ["#fff391", "#e49e28"]
      ];

      function random(min, max) {
        return min + Math.random() * (max - min);
      }

      function clamp(value, min, max) {
        return Math.max(min, Math.min(max, value));
      }

      function normalizeRadius(r) {
        const requested = Number.isFinite(Number(r)) ? Math.abs(Number(r)) : random(13, 24);
        return clamp(requested, 2, Math.min(W, H) / 2);
      }

      function drawArena() {
        const background = ctx.createLinearGradient(0, 0, 0, H);
        background.addColorStop(0, "#111728");
        background.addColorStop(1, "#080c15");
        ctx.fillStyle = background;
        ctx.fillRect(0, 0, W, H);

        ctx.save();
        ctx.strokeStyle = "rgba(128, 145, 210, 0.07)";
        ctx.lineWidth = 1;

        for (let x = 20.5; x < W; x += 40) {
          ctx.beginPath();
          ctx.moveTo(x, 0);
          ctx.lineTo(x, H);
          ctx.stroke();
        }

        for (let y = 20.5; y < H; y += 40) {
          ctx.beginPath();
          ctx.moveTo(0, y);
          ctx.lineTo(W, y);
          ctx.stroke();
        }

        const floorGlow = ctx.createLinearGradient(0, H - 70, 0, H);
        floorGlow.addColorStop(0, "rgba(86, 104, 210, 0)");
        floorGlow.addColorStop(1, "rgba(86, 104, 210, 0.14)");
        ctx.fillStyle = floorGlow;
        ctx.fillRect(0, H - 70, W, 70);
        ctx.restore();
      }

      function drawBall(ball) {
        ctx.save();

        ctx.shadowColor = ball.colors[1];
        ctx.shadowBlur = 16;

        const gradient = ctx.createRadialGradient(
          ball.x - ball.r * 0.35,
          ball.y - ball.r * 0.4,
          ball.r * 0.1,
          ball.x,
          ball.y,
          ball.r
        );
        gradient.addColorStop(0, "#ffffff");
        gradient.addColorStop(0.18, ball.colors[0]);
        gradient.addColorStop(1, ball.colors[1]);

        ctx.fillStyle = gradient;
        ctx.beginPath();
        ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
        ctx.fill();

        ctx.shadowBlur = 0;
        ctx.strokeStyle = "rgba(255,255,255,0.42)";
        ctx.lineWidth = 1.2;
        ctx.stroke();

        ctx.fillStyle = "rgba(255,255,255,0.48)";
        ctx.beginPath();
        ctx.arc(
          ball.x - ball.r * 0.3,
          ball.y - ball.r * 0.35,
          Math.max(1.5, ball.r * 0.13),
          0,
          Math.PI * 2
        );
        ctx.fill();

        ctx.restore();
      }

      function redraw() {
        drawArena();

        for (const ball of state) {
          drawBall(ball);
        }

        if (state.length === 0) {
          ctx.save();
          ctx.textAlign = "center";
          ctx.fillStyle = "rgba(188, 198, 231, 0.54)";
          ctx.font = "600 15px system-ui, sans-serif";
          ctx.fillText("Click to add a ball", W / 2, H / 2);
          ctx.restore();
        }
      }

      function addBall(x, y, vx = 0, vy = 0, r) {
        const radius = normalizeRadius(r);
        const colorPair = palette[Math.floor(Math.random() * palette.length)];
        const ball = {
          x: clamp(Number.isFinite(Number(x)) ? Number(x) : W / 2, radius, W - radius),
          y: clamp(Number.isFinite(Number(y)) ? Number(y) : radius, radius, H - radius),
          vx: Number.isFinite(Number(vx)) ? Number(vx) : 0,
          vy: Number.isFinite(Number(vy)) ? Number(vy) : 0,
          r: radius,
          colors: colorPair
        };

        state.push(ball);
        redraw();
        return ball;
      }

      function clear() {
        state.length = 0;
        redraw();
      }

      function resolveBounds(ball) {
        const left = ball.r;
        const right = W - ball.r;
        const top = ball.r;
        const bottom = H - ball.r;

        if (ball.x <= left) {
          ball.x = left;
          if (ball.vx < 0) ball.vx = -ball.vx * RESTITUTION;
        } else if (ball.x >= right) {
          ball.x = right;
          if (ball.vx > 0) ball.vx = -ball.vx * RESTITUTION;
        }

        if (ball.y <= top) {
          ball.y = top;
          if (ball.vy < 0) ball.vy = -ball.vy * RESTITUTION;
        } else if (ball.y >= bottom) {
          ball.y = bottom;
          if (ball.vy > 0) ball.vy = -ball.vy * RESTITUTION;
        }

        ball.x = clamp(ball.x, left, right);
        ball.y = clamp(ball.y, top, bottom);
      }

      function step(dt = 1) {
        dt = Number(dt);
        if (!Number.isFinite(dt) || dt < 0) dt = 1;

        let maxSpeed = 0;
        for (const ball of state) {
          maxSpeed = Math.max(maxSpeed, Math.abs(ball.vx), Math.abs(ball.vy));
        }

        const substeps = Math.min(
          160,
          Math.max(1, Math.ceil(dt), Math.ceil((maxSpeed * dt) / 12))
        );
        const slice = dt / substeps;

        for (let n = 0; n < substeps; n++) {
          for (const ball of state) {
            ball.vy += GRAVITY * slice;
            ball.x += ball.vx * slice;
            ball.y += ball.vy * slice;
            resolveBounds(ball);
          }
        }

        redraw();
      }

      function publicBalls() {
        return state.map(({ x, y, vx, vy, r }) => ({ x, y, vx, vy, r }));
      }

      window.sim = {
        w: W,
        h: H,
        balls: publicBalls,
        addBall,
        clear,
        step
      };

      canvas.addEventListener("pointerdown", event => {
        const rect = canvas.getBoundingClientRect();
        const x = (event.clientX - rect.left) * W / rect.width;
        const y = (event.clientY - rect.top) * H / rect.height;
        addBall(x, y, random(-4.2, 4.2), random(-6.5, -1.5));
      });

      dropButton.addEventListener("click", () => {
        addBall(random(55, W - 55), random(30, 65), random(-2.5, 2.5), random(-1, 1));
      });

      playButton.addEventListener("click", () => {
        running = !running;
        playButton.textContent = running ? "Pause" : "Play";
        previousTime = performance.now();
      });

      clearButton.addEventListener("click", clear);

      function animate(now) {
        if (running) {
          const elapsed = Math.min(50, now - previousTime);
          step(elapsed / (1000 / 60));
        }
        previousTime = now;
        requestAnimationFrame(animate);
      }

      addBall(W * 0.36, 105, 2.2, -0.5, 19);
      addBall(W * 0.58, 62, -1.3, 0, 15);
      redraw();
      requestAnimationFrame(animate);
    })();
  </script>
</body>
</html>
